import React from 'react';
import { Box, AppBar, Toolbar, Typography, Button, IconButton, Grid, Paper, Divider } from '@mui/material';
import { PlusIcon, BriefcaseIcon, UserIcon, ChartBarIcon } from '@heroicons/react/24/outline';
import { motion } from 'framer-motion';
import { useNavigate } from 'react-router-dom';

// Navbar Component
const Navbar: React.FC = () => {
  const navigate = useNavigate();

  const navItems = [
    { label: 'Create New Job', icon: PlusIcon, path: '/jobs/create' },
    { label: 'Jobs', icon: BriefcaseIcon, path: '/jobs' },
    { label: 'Candidate', icon: UserIcon, path: '/candidates' },
    { label: 'Report', icon: ChartBarIcon, path: '/reports' },
  ];

  return (
    <AppBar
      position="fixed"
      sx={{
        bgcolor: 'rgba(15, 23, 42, 0.95)',
        borderBottom: '1px solid rgba(59, 130, 246, 0.3)',
        boxShadow: '0 0 20px rgba(59, 130, 246, 0.2)',
      }}
    >
      <Toolbar>
        <Typography
          variant="h6"
          sx={{
            flexGrow: 1,
            fontWeight: 'bold',
            color: '#3b82f6',
            background: 'linear-gradient(45deg, #3b82f6, #9333ea)',
            WebkitBackgroundClip: 'text',
            WebkitTextFillColor: 'transparent',
          }}
        >
          HUNTER AI
        </Typography>
        {navItems.map((item) => (
          <Button
            key={item.label}
            component={motion.button}
            whileHover={{ scale: 1.05, backgroundColor: 'rgba(59, 130, 246, 0.1)' }}
            whileTap={{ scale: 0.95 }}
            onClick={() => navigate(item.path)}
            sx={{
              color: '#e2e8f0',
              textTransform: 'none',
              mx: 1,
              '&:hover': {
                color: '#3b82f6',
                backgroundColor: 'rgba(59, 130, 246, 0.1)',
              },
            }}
            startIcon={<item.icon className="h-5 w-5" />}
          >
            {item.label}
          </Button>
        ))}
      </Toolbar>
    </AppBar>
  );
};

// Dashboard Component
const Dashboard: React.FC = () => {
  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: { staggerChildren: 0.2 },
    },
  };

  const cardVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: { opacity: 1, y: 0 },
  };

  // Mock data for demonstration
  const dashboardData = {
    activeJobs: 12,
    applicantsPerJob: 45,
    candidateStages: {
      interviewed: 28,
      shortlisted: 15,
      hired: 8,
    },
    notifications: [
      { id: 1, message: 'New application for Software Engineer role', time: '2 hours ago' },
      { id: 2, message: 'AI analysis completed for Data Scientist candidates', time: '4 hours ago' },
    ],
  };

  return (
    <Box
      sx={{
        minHeight: '100vh',
        bgcolor: '#0a0f24',
        background: 'radial-gradient(circle at center, #1e3a8a 0%, #0a0f24 100%)',
        pt: 10,
        px: 4,
      }}
    >
      <style>
        {`
          @keyframes pulse {
            0% { opacity: 0.3; }
            50% { opacity: 0.6; }
            100% { opacity: 0.3; }
          }
        `}
      </style>
      <Navbar />
      <motion.div variants={containerVariants} initial="hidden" animate="visible">
        <Typography
          variant="h4"
          sx={{
            mb: 4,
            color: '#3b82f6',
            background: 'linear-gradient(45deg, #3b82f6, #9333ea)',
            WebkitBackgroundClip: 'text',
            WebkitTextFillColor: 'transparent',
            fontWeight: 'bold',
            textAlign: 'center',
          }}
        >
          Dashboard Overview
        </Typography>
        <Grid container spacing={3}>
          {/* Active Job Posts */}
          <Grid item xs={12} sm={6} md={3}>
            <motion.div variants={cardVariants}>
              <Paper
                sx={{
                  p: 3,
                  bgcolor: 'rgba(15, 23, 42, 0.95)',
                  border: '1px solid rgba(59, 130, 246, 0.3)',
                  borderRadius: 2,
                  boxShadow: '0 0 20px rgba(59, 130, 246, 0.2)',
                  '&:hover': {
                    transform: 'translateY(-4px)',
                    boxShadow: '0 0 30px rgba(59, 130, 246, 0.3)',
                    transition: 'all 0.3s ease',
                  },
                }}
              >
                <Typography variant="h6" color="#94a3b8">
                  Active Job Posts
                </Typography>
                <Typography variant="h3" color="#3b82f6" sx={{ fontWeight: 'bold' }}>
                  {dashboardData.activeJobs}
                </Typography>
              </Paper>
            </motion.div>
          </Grid>
          {/* Applicants Per Job */}
          <Grid item xs={12} sm={6} md={3}>
            <motion.div variants={cardVariants}>
              <Paper
                sx={{
                  p: 3,
                  bgcolor: 'rgba(15, 23, 42, 0.95)',
                  border: '1px solid rgba(59, 130, 246, 0.3)',
                  borderRadius: 2,
                  boxShadow: '0 0 20px rgba(59, 130, 246, 0.2)',
                  '&:hover': {
                    transform: 'translateY(-4px)',
                    boxShadow: '0 0 30px rgba(59, 130, 246, 0.3)',
                    transition: 'all 0.3s ease',
                  },
                }}
              >
                <Typography variant="h6" color="#94a3b8">
                  Applicants/Job
                </Typography>
                <Typography variant="h3" color="#3b82f6" sx={{ fontWeight: 'bold' }}>
                  {dashboardData.applicantsPerJob}
                </Typography>
              </Paper>
            </motion.div>
          </Grid>
          {/* Candidate Stages */}
          <Grid item xs={12} sm={6} md={3}>
            <motion.div variants={cardVariants}>
              <Paper
                sx={{
                  p: 3,
                  bgcolor: 'rgba(15, 23, 42, 0.95)',
                  border: '1px solid rgba(59, 130, 246, 0.3)',
                  borderRadius: 2,
                  boxShadow: '0 0 20px rgba(59, 130, 246, 0.2)',
                  '&:hover': {
                    transform: 'translateY(-4px)',
                    boxShadow: '0 0 30px rgba(59, 130, 246, 0.3)',
                    transition: 'all 0.3s ease',
                  },
                }}
              >
                <Typography variant="h6" color="#94a3b8">
                  Candidate Stages
                </Typography>
                <Typography color="#e2e8f0">
                  Interviewed: {dashboardData.candidateStages.interviewed}
                </Typography>
                <Typography color="#e2e8f0">
                  Shortlisted: {dashboardData.candidateStages.shortlisted}
                </Typography>
                <Typography color="#e2e8f0">
                  Hired: {dashboardData.candidateStages.hired}
                </Typography>
              </Paper>
            </motion.div>
          </Grid>
          {/* Notifications */}
          <Grid item xs={12} sm={6} md={3}>
            <motion.div variants={cardVariants}>
              <Paper
                sx={{
                  p: 3,
                  bgcolor: 'rgba(15, 23, 42, 0.95)',
                  border: '1px solid rgba(59, 130, 246, 0.3)',
                  borderRadius: 2,
                  boxShadow: '0 0 20px rgba(59, 130, 246, 0.2)',
                  '&:hover': {
                    transform: 'translateY(-4px)',
                    boxShadow: '0 0 30px rgba(59, 130, 246, 0.3)',
                    transition: 'all 0.3s ease',
                  },
                }}
              >
                <Typography variant="h6" color="#94a3b8" sx={{ mb: 2 }}>
                  Notifications
                </Typography>
                {dashboardData.notifications.map((notification) => (
                  <Box key={notification.id} sx={{ mb: 1 }}>
                    <Typography color="#e2e8f0" variant="body2">
                      {notification.message}
                    </Typography>
                    <Typography color="#64748b" variant="caption">
                      {notification.time}
                    </Typography>
                    <Divider sx={{ my: 1, bgcolor: 'rgba(59, 130, 246, 0.2)' }} />
                  </Box>
                ))}
              </Paper>
            </motion.div>
          </Grid>
        </Grid>
      </motion.div>
    </Box>
  );
};

export default Dashboard;
